import json

def create_monday_item(board_id, item_name, column_values):
    '''Crear item con valores de columnas.'''
    # column_values debe ser JSON string
    cv_str = json.dumps(json.dumps(column_values))

    query = f'''mutation {{
        create_item(
            board_id: {board_id},
            item_name: "{item_name}",
            column_values: {cv_str}
        ) {{
            id
        }}
    }}'''
    return monday_query(query)

