def update_column(board_id, item_id, column_id, value):
    '''Actualizar valor de una columna.'''
    if isinstance(value, dict):
        value_str = json.dumps(json.dumps(value))
    else:
        value_str = json.dumps(json.dumps(str(value)))

    query = f'''mutation {{
        change_column_value(
            board_id: {board_id},
            item_id: {item_id},
            column_id: "{column_id}",
            value: {value_str}
        ) {{ id }}
    }}'''
    return monday_query(query)

