def batch_update_items(board_id, updates):
    '''updates: list of {item_id, column_id, value}'''
    mutations = []
    for i, u in enumerate(updates):
        value_str = json.dumps(u['value']) if isinstance(u['value'], dict) else json.dumps(str(u['value']))
        mutations.append(f'''
            m{i}: change_column_value(
                board_id: {board_id},
                item_id: {u['item_id']},
                column_id: "{u['column_id']}",
                value: {json.dumps(value_str)}
            ) {{ id }}
        ''')

    query = 'mutation {' + ''.join(mutations) + '}'
    return monday_query(query)

