import requests

def upload_file(api_token, item_id, column_id, file_path):
    '''Sube archivo a columna de archivos.'''
    query = '''mutation($file: File!) {
        add_file_to_column(
            item_id: ITEM_ID,
            column_id: "COLUMN_ID",
            file: $file
        ) { id }
    }'''.replace('ITEM_ID', str(item_id)).replace('COLUMN_ID', column_id)

    with open(file_path, 'rb') as f:
        files = {
            'query': (None, query),
            'variables[file]': (file_path.split('/')[-1], f, 'application/octet-stream'),
        }
        r = requests.post(
            'https://api.monday.com/v2/file',
            headers={'Authorization': api_token},
            files=files
        )
    return r.json()

